const input = $input.first().json;

console.log('=== PAYLOAD RECIBIDO ===');
console.log('input.body:', JSON.stringify(input.body, null, 2));
console.log('input:', JSON.stringify(input, null, 2));

// n8n puede entregar el payload directo o dentro de body
const data = input.body || input;

const value = data.entry?.[0]?.changes?.[0]?.value;

// Ignorar estados de WhatsApp: delivered/read/sent
if (value?.statuses && !value?.messages) {
  return [];
}

let channel = 'unknown';
let from = 'anonymous';
let message = '';
let userName = '';

// 1. WHATSAPP META
if (data.entry?.[0]?.changes?.[0]?.value?.messages) {
  channel = 'whatsapp';

  const value = data.entry[0].changes[0].value;
  const msg = value.messages[0];

  from = msg.from || '';

  if (msg.type === 'text') {
    message = msg.text?.body || '';
  } else if (msg.type === 'interactive') {
    message =
      msg.interactive?.button_reply?.title ||
      msg.interactive?.button_reply?.id ||
      msg.interactive?.list_reply?.title ||
      msg.interactive?.list_reply?.id ||
      '';
  } else {
    message = '[Archivo recibido - por favor escribe tu consulta]';
  }

  userName = value.contacts?.[0]?.profile?.name || 'Paciente WhatsApp';
}

// 2. INSTAGRAM
else if (data.object === 'instagram' && data.entry?.[0]?.messaging) {
  channel = 'instagram';
  const msg = data.entry[0].messaging[0];  // ← msg se define aquí

  const BOT_PSID = $env.META_BOT_PSID;

  // 1. Ignorar echo del bot
  if (msg.message?.is_echo || msg.sender?.id === BOT_PSID) {
    return [{ json: { channel: 'ignorar', from: '', message: '',
      conversationId: 'ignorar:echo', userName: '',
      timestamp: new Date().toISOString() } }];
  }

  // 2. Ignorar read receipts
  if (msg.read) {
    return [{ json: { channel: 'ignorar', from: '', message: '',
      conversationId: 'ignorar:read', userName: '',
      timestamp: new Date().toISOString() } }];
  }

  // 3. Ignorar mensajes vacíos
  if (!msg.message?.text && !msg.message?.attachments) {
    return [{ json: { channel: 'ignorar', from: '', message: '',
      conversationId: 'ignorar:empty', userName: '',
      timestamp: new Date().toISOString() } }];
  }

  from = msg.sender?.id || '';
  message = msg.message?.text || (msg.message?.attachments ? '[Archivo adjunto]' : '');
  userName = 'Paciente Instagram';
}

// 3. FACEBOOK
else if (data.object === 'page' && data.entry?.[0]?.messaging) {
  channel = 'facebook';
  const msg = data.entry[0].messaging[0];
  const BOT_PAGE_ID = $env.META_BOT_PSID;

  // Ignorar echo del bot
  if (msg.message?.is_echo || msg.sender?.id === BOT_PAGE_ID) {
    return [{ json: { channel: 'ignorar', from: '', message: '',
      conversationId: 'ignorar:echo', userName: '',
      timestamp: new Date().toISOString() } }];
  }

  // Ignorar read receipts
  if (msg.read) {
    return [{ json: { channel: 'ignorar', from: '', message: '',
      conversationId: 'ignorar:read', userName: '',
      timestamp: new Date().toISOString() } }];
  }

  // Ignorar mensajes vacíos
  if (!msg.message?.text && !msg.message?.attachments) {
    return [{ json: { channel: 'ignorar', from: '', message: '',
      conversationId: 'ignorar:empty', userName: '',
      timestamp: new Date().toISOString() } }];
  }

  from = msg.sender?.id || '';
  message = msg.message?.text || (msg.message?.attachments ? '[Archivo adjunto]' : '');
  userName = 'Paciente Facebook';
}
// 4. TEST / NORMALIZADO
else {
  channel = data.channel || input.channel || 'test';
  from = data.from || input.from || data.user_id || input.user_id || 'test_user';
  message = data.message || input.message || data.text || input.text || '';
  userName = data.user_name || data.userName || input.user_name || input.userName || 'Usuario Test';
}

// Normalizar
channel = String(channel || 'test').toLowerCase().trim();

if (channel === 'whatsapp') {
  // WhatsApp sí necesita solo números
  from = String(from || '').replace(/\D/g, '');
} else {
  // En test/instagram/facebook conservar identificador completo
  from = String(from || 'test_user').trim();
}

message = String(message || '').trim();;

const conversationId = `${channel}:${from}`;
const timestamp = new Date().toISOString();

let incomingMessageId = '';

try {
  if (channel === 'whatsapp') {
    incomingMessageId =
      data.entry?.[0]?.changes?.[0]?.value?.messages?.[0]?.id || '';
  }

  if (channel === 'instagram' || channel === 'facebook') {
    incomingMessageId =
      data.entry?.[0]?.messaging?.[0]?.message?.mid ||
      data.entry?.[0]?.messaging?.[0]?.postback?.mid ||
      '';
  }

  if (!incomingMessageId) {
    incomingMessageId = `${channel}:${from}:${message}:${Math.floor(Date.now() / 5000)}`;
  }

  const staticData = $getWorkflowStaticData('global');
  staticData.processedMessages = staticData.processedMessages || {};

  if (staticData.processedMessages[incomingMessageId]) {
    return [];
  }

  staticData.processedMessages[incomingMessageId] = new Date().toISOString();

  const ids = Object.keys(staticData.processedMessages);
  if (ids.length > 1000) {
    for (const id of ids.slice(0, ids.length - 1000)) {
      delete staticData.processedMessages[id];
    }
  }
} catch (e) {
  // Si falla el anti-duplicado, no bloqueamos el flujo
}

if (!message || message.trim() === '') {
  return [];
}

return [{
  json: {
    channel,
    from,
    message,
    conversationId,
    userName,
    timestamp,
    _webhookData: {
      channel,
      from,
      message,
      conversationId,
      userName,
      timestamp,
      raw: data
    }
  }
}];

const input = $input.first().json;
const conversationId = input.conversationId || 'unknown';
const now = Date.now();

const WINDOW_MS = 60000;
const MAX = 8;

try {
  const staticData = $getWorkflowStaticData('global');
  staticData.rateLimiter = staticData.rateLimiter || {};

  const key = `rate:${conversationId}`;
  let d = staticData.rateLimiter[key] || { timestamps: [], blockedUntil: null };

  if (d.blockedUntil && d.blockedUntil > now) {
    const wait = Math.ceil((d.blockedUntil - now) / 1000);
    return [{ json: { ...input, rateLimited: true, errorMessage: `Demasiados mensajes. Espera ${wait} segundos.` } }];
  }

  d.timestamps = (d.timestamps || []).filter(t => now - t < WINDOW_MS);

  if (d.timestamps.length >= MAX) {
    d.blockedUntil = now + WINDOW_MS;
    staticData.rateLimiter[key] = d;
    return [{ json: { ...input, rateLimited: true, errorMessage: 'Demasiados mensajes. Espera 1 minuto.' } }];
  }

  d.timestamps.push(now);
  d.blockedUntil = null;
  staticData.rateLimiter[key] = d;

  const keys = Object.keys(staticData.rateLimiter);
  if (keys.length > 2000) {
    for (const oldKey of keys.slice(0, keys.length - 2000)) {
      delete staticData.rateLimiter[oldKey];
    }
  }
} catch (e) {
  console.log('Rate limiter staticData no disponible:', e.message);
}

return [{ json: { ...input, rateLimited: false } }];

const allItems = $input.all().map(i => i.json);

const base =
  allItems.find(i => i.conversationId || i.context?.conversationId || i._webhookData?.conversationId) ||
  {};

const eventos = allItems.filter(i => i.start && i.end && i.id);

const CONFIG = base.CONFIG || {};
const INICIO = CONFIG.horario?.inicio ?? 10;
const FIN    = CONFIG.horario?.fin ?? 19;
const DUR    = CONFIG.horario?.duracion_cita ?? 60;
const LAB    = CONFIG.horario?.dias_laborables ?? [1, 2, 3, 4, 5];

const ocupados = eventos
  .map(i => ({
    id: i.id,
    ini: new Date(i.start.dateTime || i.start.date),
    fin: new Date(i.end.dateTime || i.end.date)
  }))
  .filter(e => !isNaN(e.ini));

const TZ = 'Europe/Madrid';

function madridDateToUTC(year, month, day, hour, minute = 0) {
  // Convierte una fecha/hora local de Europe/Madrid a UTC respetando horario de verano/invierno.
  const utcGuess = new Date(Date.UTC(year, month - 1, day, hour, minute, 0, 0));

  const asMadrid = new Date(utcGuess.toLocaleString('en-US', { timeZone: TZ }));
  const asUTC = new Date(utcGuess.toLocaleString('en-US', { timeZone: 'UTC' }));
  const offsetMs = asMadrid.getTime() - asUTC.getTime();

  return new Date(utcGuess.getTime() - offsetMs);
}

function labelMadrid(dateUTC) {
  return (
    dateUTC.toLocaleDateString('es-ES', {
      weekday: 'long',
      day: 'numeric',
      month: 'long',
      timeZone: TZ
    }) +
    ' a las ' +
    dateUTC.toLocaleTimeString('es-ES', {
      hour: '2-digit',
      minute: '2-digit',
      timeZone: TZ
    })
  );
}

const slots = [];
const ahora = new Date();

for (let d = 0; d < 7; d++) {
  const baseMadrid = new Date(
    ahora.toLocaleString('en-US', { timeZone: TZ })
  );

  baseMadrid.setDate(baseMadrid.getDate() + d);

  const year = baseMadrid.getFullYear();
  const month = baseMadrid.getMonth() + 1;
  const day = baseMadrid.getDate();

  const dow = baseMadrid.getDay();
  if (!LAB.includes(dow)) continue;

  for (let h = INICIO; h < FIN; h++) {
    const si = madridDateToUTC(year, month, day, h, 0);
    const sf = new Date(si.getTime() + DUR * 60000);

    if (si <= new Date(Date.now() + 3600000)) continue;

    const libre = !ocupados.some(e => si < e.fin && sf > e.ini);

    if (libre) {
      slots.push({
        inicio: si.toISOString(),
        fin: sf.toISOString(),
        label: labelMadrid(si)
      });
    }
  }
}

const top8 = slots.slice(0, 8);
const texto =
  top8.map((s, i) => `${i + 1}. ${s.label}`).join('\n') ||
  'Sin disponibilidad esta semana.';

return [{
  json: {
    ...base,
    slotsDisponibles: top8,
    slotsTexto: texto,
    totalSlots: slots.length,
    eventosCalendarOcupados: ocupados.length,
    debugOcupados: ocupados.map(e => ({
      id: e.id,
      ini: e.ini.toISOString(),
      fin: e.fin.toISOString()
    }))
  }
}];

