const allItems = $input.all().map(i => i.json);
const merged = Object.assign({}, ...allItems);

const geminiText = merged.candidates?.[0]?.content?.parts?.[0]?.text || '';

let cat = 'OTRO', resp = '', srv = null, slot = null;
let escalar = false, cita = false;
let datos = {}, motivoEscalado = null, confianza = 0.5;

const etapasValidas = [
  'inicio',
  'triaje',
  'recopilando_nombre',
  'recopilando_telefono',
  'mostrando_slots',
  'confirmando_cita',
  'agendado',
  'escalar'
];

function pareceNombre(texto) {
  const t = String(texto || '').trim();
  const n = t.toLowerCase();

  if (!t) return false;
  if (/\d/.test(t)) return false;
  if (t.length < 3) return false;

  const frasesNoNombre = [
    'hola',
    'buenas',
    'buenos dias',
    'buenos días',
    'buenas tardes',
    'buenas noches',
    'quiero',
    'quisiera',
    'me gustaría',
    'me gustaria',
    'necesito',
    'me interesa',
    'información',
    'informacion',
    'precio',
    'cuánto',
    'cuanto',
    'consulta',
    'cita',
    'agendar',
    'reservar',
    'tratamiento',
    'servicio',
    'disponibilidad',
    'horario',
    'duda',
    'pregunta'
  ];

  return !frasesNoNombre.some(p => n.includes(p));
}

function normalizarTelefonoES(texto) {
  let t = String(texto || '').replace(/\D/g, '');

  if (t.startsWith('0034')) t = t.slice(4);
  if (t.startsWith('34') && t.length === 11) t = t.slice(2);

  if (/^[6-7]\d{8}$/.test(t)) {
    return '34' + t;
  }

  return null;
}

try {
  let text = geminiText
    .replace(/```json\s*/gi, '')
    .replace(/```\s*/gi, '')
    .trim();

  if (!text.startsWith('{')) {
    const match = geminiText.match(/\{[\s\S]*\}/);
    text = match ? match[0] : '{}';
  }

  const p = JSON.parse(text);

  cat             = p.intencion || 'OTRO';
  resp            = p.respuesta || '';
  srv             = (p.servicio && p.servicio !== 'null') ? p.servicio : null;
  slot            = (p.slotElegido && p.slotElegido !== 'null') ? p.slotElegido : null;
  escalar         = p.escalarHumano === true;
  cita            = p.citaLista === true;
  datos           = p.datosRecopilados || {};
  motivoEscalado  = (p.motivoEscalado && p.motivoEscalado !== 'null') ? p.motivoEscalado : null;
  confianza       = p.confianzaIntencion || 0.5;

} catch (e) {
  resp = 'Hola! Soy Sofia. ¿En qué puedo ayudarte?';
  cat = 'OTRO';
}

const validas = [
  'CONSULTA',
  'AGENDAR',
  'CANCELAR_CITA',
  'CAMBIAR_CITA',
  'CUALIFICACION',
  'ESCALAR_HUMANO',
  'CONFIRMACION_CITA',
  'DESPEDIDA',
  'OTRO'
];

if (!validas.includes(cat)) cat = 'OTRO';
if (cat === 'ESCALAR_HUMANO') escalar = true;

// Actualizar solo metadata del contexto - NO actualizar stage, lo hace el Motor
const ctx = merged.context || {};
ctx.metadata = ctx.metadata || {};

const stageActual = ctx.stage || 'inicio';

// Nombre: SOLO guardar si estamos realmente pidiendo el nombre
if (
  stageActual === 'recopilando_nombre' &&
  datos.nombre &&
  datos.nombre !== 'null' &&
  pareceNombre(datos.nombre)
) {
  ctx.metadata.nombre = String(datos.nombre).trim();
}

// Teléfono: normalizar antes de guardar
if (datos.telefono && datos.telefono !== 'null') {
  const telefonoNormalizado = normalizarTelefonoES(datos.telefono);

  if (telefonoNormalizado) {
    ctx.metadata.telefono = telefonoNormalizado;
  }
}

// Edad: se puede guardar si Gemini la detecta, pero sin tocar stage
if (datos.edad && datos.edad !== 'null') {
  ctx.metadata.edad = datos.edad;
}

// Condición médica
if (datos.condicionMedica && datos.condicionMedica !== 'null') {
  ctx.metadata.condiciones = ctx.metadata.condiciones || [];

  if (!ctx.metadata.condiciones.includes(datos.condicionMedica)) {
    ctx.metadata.condiciones.push(datos.condicionMedica);
  }
}

if (motivoEscalado || escalar === true || cat === 'ESCALAR_HUMANO') {
  ctx.metadata.motivoEscalado = motivoEscalado || 'Escalado a humano';

  ctx.metadata.human_takeover = true;
  ctx.metadata.human_takeover_reason =
    motivoEscalado || 'Escalado a humano';

  ctx.metadata.human_takeover_at =
    new Date().toISOString();
}

// Tratamiento de interés
if (srv) {
  ctx.metadata.tratamientos_interes = ctx.metadata.tratamientos_interes || [];

  if (!ctx.metadata.tratamientos_interes.includes(srv)) {
    ctx.metadata.tratamientos_interes.push(srv);
  }
}

ctx.intencion = cat;
// NO tocar ctx.stage aquí - el Motor de Estado lo gestiona

return [{
  json: {
    ...merged,
    context: ctx,
    categoriaIA: cat,
    respuestaIA: resp,
    servicio: srv,
    slotElegido: slot,
    escalarHumano: escalar,
    citaLista: cita,
    datosRecopilados: datos,
    motivoEscalado,
    confianzaIntencion: confianza
  }
}];

// PREPARAR CITA - Usa slot elegido por el Motor de Estado
const input = $input.first().json;
const meta = input.context?.metadata || {};

// El Motor de Estado ya calculó el slot exacto
const slotData = input.slotElegidoMotor || meta.slotPropuesto;

let slotIni, slotFin;
if (slotData && slotData.inicio) {
  slotIni = new Date(slotData.inicio);
  slotFin = new Date(slotData.fin || slotIni.getTime() + 3600000);
} else if (input.slotElegido && input.slotElegido !== 'null') {
  slotIni = new Date(input.slotElegido);
  slotFin = new Date(slotIni.getTime() + 3600000);
} else {
  // Fallback: primer slot disponible
  const slots = input.slotsDisponibles || [];
  if (slots.length > 0) {
    slotIni = new Date(slots[0].inicio);
    slotFin = new Date(slots[0].fin);
  } else {
    slotIni = new Date();
    slotIni.setDate(slotIni.getDate() + 2);
    slotIni.setHours(10, 0, 0, 0);
    slotFin = new Date(slotIni.getTime() + 3600000);
  }
}

const servicio = input.servicio || meta.tratamientos_interes?.[0] || 'Consulta General';
const nombre = meta.nombre || input.userName || 'Paciente';
const telefono = meta.telefono || input.from;

return [{
  json: {
    ...input,
    slotInicio: slotIni.toISOString(),
    slotFin: slotFin.toISOString(),
    servicioFinal: servicio,
    nombrePaciente: nombre,
    telefonoPaciente: telefono,
    calendarEvent: {
      summary: `${servicio} - ${nombre}`,
      description: `Paciente: ${nombre}\nCanal: ${input.channel}\nTelefono: ${telefono}\nTratamiento: ${servicio}\nConversacion: ${input.conversationId}`
    }
  }
}];

const cita = $('Detectar y Preparar Cita').first().json;

let ev = {};

try {
  ev = $('Actualizar Evento Calendar').first().json;
} catch (e) {
  try {
    ev = $('Crear Evento Calendar').first().json;
  } catch (e2) {
    ev = {};
  }
}

const config = cita.CONFIG || cita.config || {};
const meta = cita.context?.metadata || {};

const direccion = config?.clinica?.direccion || 'TU_DIRECCION_CLINICA';
const nombreClinica = config?.clinica?.nombre || 'Clínica';

const nombre = cita.nombrePaciente || meta.nombre || cita.userName || 'Paciente';
const telefono = cita.telefonoPaciente || meta.telefono || cita.telefonoBusqueda || cita.from || '';
const servicio = cita.servicioFinal || cita.servicio || meta.tratamientos_interes?.[0] || 'Consulta';

const slotInicio = cita.slotInicio || ev.start?.dateTime || ev.start?.date || '';
const slotFin = cita.slotFin || ev.end?.dateTime || ev.end?.date || '';

const start = slotInicio ? new Date(slotInicio) : new Date();

const TZ = 'Europe/Madrid';

const fecha = start.toLocaleDateString('es-ES', {
  weekday: 'long',
  day: 'numeric',
  month: 'long',
  year: 'numeric',
  timeZone: TZ
});

const hora = start.toLocaleTimeString('es-ES', {
  hour: '2-digit',
  minute: '2-digit',
  timeZone: TZ
});

const calendarEventId = ev.id || ev.calendarEventId || '';
const calendarHtmlLink = ev.htmlLink || '';

const msg = `✅ Cita confirmada ${nombre}!

📅 ${fecha}
🕒 ${hora}
💉 Tratamiento: ${servicio}
📍 ${direccion}

Te avisaremos 24h antes. Si necesitas cancelar, avisa con al menos 24h de antelación.

¡Te esperamos en ${nombreClinica}!`;

return [
  {
    json: {
      ...cita,

      channel: cita.channel || cita.context?.channel || 'whatsapp',
      from: cita.from || '',
      conversationId: cita.conversationId || cita.context?.conversationId || '',
      userName: cita.userName || cita.context?.userName || 'Paciente',

      message: msg,
      respuestaIA: msg,
      categoriaIA: 'CONFIRMACION_CITA',

      citaConfirmada: true,
      citaLista: true,

      calendarEventId,
      calendarHtmlLink,

      slotInicio,
      slotFin,

      nombrePaciente: nombre,
      telefonoPaciente: telefono,
      servicioFinal: servicio,

      tipoEvento: 'CITA_CONFIRMADA',

      context: {
        ...(cita.context || {}),
        stage: 'agendado',
        metadata: {
          ...(meta || {}),
          nombre,
          telefono,
          slotPropuesto: meta.slotPropuesto || cita.slotElegidoMotor || null,
          tratamientoConfirmado: servicio,
          calendarEventId,
          citaConfirmada: true,
          confirmacionEnProceso: false,
          confirmacionEnProcesoAt: null
        }
      },

      crmEvento: {
        event_id: `EVT-${Date.now()}`,
        patient_id: cita.patientId || cita.context?.patientId || '',
        paciente_nombre: nombre,
        paciente_telefono: telefono,
        tipo_evento: 'CITA_CONFIRMADA',
        prioridad: 'MEDIA',
        etapa_actual: 'agendado',
        mensaje_paciente:
