function normalizar(str) {
  return (str || '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .trim();
}

function normalizarTelefonoES(texto) {
  let t = String(texto || '').replace(/\D/g, '');
  if (t.startsWith('0034')) t = t.slice(4);
  if (t.startsWith('34') && t.length === 11) t = t.slice(2);
  if (/^[6-7]\d{8}$/.test(t)) return '34' + t;
  return null;
}

function esTelefono(str) {
  return !!normalizarTelefonoES(str);
}

function pareceNombre(texto) {
  const t = String(texto || '').trim();
  const n = normalizar(t);
  if (!t) return false;
  if (/\d/.test(t)) return false;
  if (t.length < 3) return false;
  if (t.length > 60) return false;
  const frasesNoNombre = [
    'hola', 'buenas', 'buenos dias', 'buenas tardes', 'buenas noches',
    'quiero', 'quisiera', 'me gustaria', 'necesito', 'me interesa',
    'informacion', 'precio', 'cuanto', 'consulta', 'cita', 'agendar',
    'reservar', 'tratamiento', 'servicio', 'disponibilidad', 'horario',
    'duda', 'pregunta', 'presupuesto', 'valoracion', 'clinica'
  ];
  if (frasesNoNombre.some(p => n.includes(p))) return false;
  const palabras = t.split(/\s+/).filter(p => p.length > 1);
  return palabras.length >= 1 && palabras.length <= 5;
}

function nombreValidoGuardado(nombre) {
  return pareceNombre(nombre);
}

function formatearSlots(slots) {
  return (slots || [])
    .slice(0, 6)
    .map((s, i) => `${i + 1}. ${s.label}`)
    .join('\n');
}

function esDespedida(texto) {
  const t = normalizar(texto);
  return [
    'adios', 'hasta luego', 'bye', 'no gracias', 'no quiero',
    'nada mas', 'dejalo', 'dejalo estar', 'no me interesa',
    'gracias adios', 'no quiero nada', 'no necesito nada',
    'hasta pronto', 'me voy', 'no hace falta', 'no pasa nada',
    'muchas gracias', 'gracias', 'perfecto gracias',
    'ok gracias', 'genial gracias', 'de acuerdo gracias',
    'vale gracias', 'vale', 'bien', 'ok gracias',
    'thank you', 'thanks'
  ].some(p => t.includes(normalizar(p)));
}

