      const nombreYaExiste = nombreValidoGuardado(metadata.nombre);
      const telefonoNormalizado = normalizarTelefonoES(metadata.telefono);
      const telefonoYaExiste = !!telefonoNormalizado;

      if (telefonoNormalizado) metadata.telefono = telefonoNormalizado;

      if (!nombreYaExiste) {
        nuevaEtapa = 'recopilando_nombre';
        respuesta = `Perfecto, gracias! ✅\n\n¿Cuál es tu nombre completo para la reserva?`;

