function normalizarTelefono(str) {
  if (!str) return null;
  let limpio = str.replace(/[\s\-\.\(\)]/g, '');
  if (limpio.startsWith('+34')) limpio = limpio.slice(3);
  if (limpio.startsWith('34') && limpio.length === 11) limpio = limpio.slice(2);
  if (/^[6789]\d{8}$/.test(limpio)) return limpio;
  return null;
}

function extraerTelefonoDeTexto(texto) {
  const patrones = [
    /(?:\+34|34)?[\s\-]?[6789][\s\-]?\d{2}[\s\-]?\d{2}[\s\-]?\d{2}[\s\-]?\d{2}/g,
    /[6789]\d{8}/g
  ];
  for (const patron of patrones) {
    const matches = texto.match(patron);
    if (matches) {
      for (const m of matches) {
        const norm = normalizarTelefono(m);
        if (norm) return norm;
      }
    }
  }
  return null;
}

