let leads_cualificados = parseInt(metrics.leads_cualificados) || 0;
let citas_agendadas = parseInt(metrics.citas_agendadas) || 0;
let citas_completadas = parseInt(metrics.citas_completadas) || 0;
let escalados = parseInt(metrics.escalados) || 0;

