if (tipoEvento === 'ESCALADO' || tipoEvento === 'ESCALAR_HUMANO') escalados++;
if (tipoEvento === 'CITA_CANCELADA') citas_completadas++;

const conversion_rate =
  total_leads > 0 ? (citas_agendadas / total_leads) * 100 : 0;

