  phone = '34' + phone;
}

let email =
  meta.email ||
  input.email ||
  crm.paciente_email ||
  '';

// Si es canal test y no hay datos, usar valores ficticios
if (input.channel === 'test') {
  const unique = String(Date.now()).slice(-9);

  phone = `6${unique.slice(1)}`;

  email = `test_${String(input.conversationId || Date.now()).replace(/[^a-zA-Z0-9]/g, '_')}_${Date.now()}@example.com`;
}

const tipoEvento =
  input.tipoEvento ||
  crm.tipo_evento ||
  (input.citaConfirmada ? 'CITA_CONFIRMADA' : input.escalarHumano ? 'ESCALADO' : 'LEAD');

if (!phone && !email && tipoEvento !== 'ESCALADO') {
  return [{
    json: {
      ...input,
      enviarGHL: false
    }
  }];
}

const servicio =
  input.servicioFinal ||
  crm.servicio ||
  meta.tratamientoConfirmado ||
  meta.tratamientos_interes?.[0] ||
  'Consulta';

let stageId = $env.GHL_STAGE_NUEVO_LEAD;

if (tipoEvento === 'CITA_CONFIRMADA') stageId = $env.GHL_STAGE_CITA_CONFIRMADA;
if (tipoEvento === 'ESCALADO') stageId = $env.GHL_STAGE_ESCALADO;
if (tipoEvento === 'CITA_CANCELADA') stageId = $env.GHL_STAGE_CANCELADO;

const tags = [
  'ai-agent',
  `canal-${input.channel || 'unknown'}`,
  tipoEvento.toLowerCase()
];

if (input.escalarHumano) tags.push('requiere-humano');
if (input.citaConfirmada) tags.push('cita-confirmada');

const note = [
  `Evento: ${tipoEvento}`,
  `Canal: ${input.channel || ''}`,
  `Conversación: ${input.conversationId || ''}`,
  `Servicio: ${servicio}`,
  `Fecha cita: ${input.slotInicio || crm.cita_fecha || ''}`,
  `Calendar ID: ${input.calendarEventId || crm.calendar_event_id || ''}`,
  ``,
  `Último mensaje paciente: ${input._webhookData?.message || crm.mensaje_paciente || ''}`,
  ``,
  `Respuesta bot: ${input.message || crm.respuesta_bot || ''}`
].join('\n');

function emailValido(email) {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(String(email || '').trim());
}

const contactPayload = {
  locationId: $env.GHL_LOCATION_ID,
  firstName: firstName || '',
  lastName: lastName || '',
  name: nombreCompleto || '',
  phone: phone || '',
  tags: tags,
  source: `AI ${input.channel || 'omnichannel'}`
};

if (emailValido(email)) {
  contactPayload.email = String(email).trim().toLowerCase();
}

return [{
  json: {
    ...input,
    debugEnv: {
  pipeline: $env.GHL_PIPELINE_ID,
  stageNuevo: $env.GHL_STAGE_NUEVO_LEAD,
  stageEscalado: $env.GHL_STAGE_ESCALADO,
  stageCita: $env.GHL_STAGE_CITA_CONFIRMADA,
  stageCancelado: $env.GHL_STAGE_CANCELADO
},
    ghl: {
      contactPayload,
      opportunityPayload: {
        locationId: $env.GHL_LOCATION_ID,
        pipelineId: $env.GHL_PIPELINE_ID,
        pipelineStageId: stageId,
        name: `${servicio} - ${nombreCompleto}`,
        monetaryValue: 0,
        status: tipoEvento === 'CITA_CANCELADA' ? 'lost' : 'open'
      },
      notePayload: {
        body: note
      },
      tipoEvento
    },
    enviarGHL: true
  }
}];

const actual = $input.first().json;
const raw = actual._webhookData?.raw || {};

// Base principal del flujo
let base = {};
try {
  base = $('Preparar Respuesta Final').first().json;
} catch (e) {
  try {
    base = $('Guardar Contexto Cache').first().json;
  } catch (e2) {
    base = actual;
  }
}

// Si viene payload manual/webhook, debe poder mandar sobre base
const input = {
  ...base,
  ...actual,
  _webhookData: {
    ...(base._webhookData || {}),
    ...(actual._webhookData || {}),
    raw
  },
  emailResponse: actual.id || actual.threadId ? actual : actual.emailResponse,
  metricsResponse: actual.metricsResponse || null,
  _ultimoNodoAntesGHL: actual
};

let meta = input.context?.metadata || {};
if (typeof meta === 'string') {
  try {
    meta = JSON.parse(meta);
  } catch (e) {
    meta = {};
  }
}

let tipoEvento =
  input.tipoEvento ||
  input.tipo_evento ||
  input.crmEvento?.tipo_evento ||
  input.alertaCRM?.tipo ||
  raw.tipo_evento ||
  '';

if (!tipoEvento) {
  if (input.accionMotor === 'ESCALAR' || input.escalarHumano === true) {
    tipoEvento = 'ESCALADO';
  } else if (
    input.citaConfirmada === true ||
    input.context?.metadata?.citaConfirmada === true ||
    input.calendarEventId
  ) {
    tipoEvento = 'CITA_CONFIRMADA';
  } else if (input.categoriaIA === 'SLOT_OCUPADO') {
    tipoEvento = 'SLOT_OCUPADO';
  } else if (input.accionMotor === 'CANCELAR_CITA') {
    tipoEvento = 'CITA_CANCELADA';
  } else if (input.accionMotor === 'AGENDAR') {
    tipoEvento = 'INTENTO_AGENDAR';
  }
}

const servicio =
  input.servicioFinal ||
  input.servicio ||
  input.crmEvento?.servicio ||
  raw.servicio ||
  meta.tratamientoConfirmado ||
  meta.tratamientos_interes?.[0] ||
  'Consulta';

const nombre =
  input.nombrePaciente ||
  input.crmEvento?.paciente_nombre ||
  raw.nombre ||
  meta.nombre ||
  input.userName ||
  'Paciente';

const telefono =
  input.telefonoPaciente ||
  input.crmEvento?.paciente_telefono ||
  raw.telefono ||
  meta.telefono ||
  input.from ||
  '';

const motivo =
  input.motivoEscalado ||
  input.crmEvento?.notas_staff ||
  meta.motivoEscalado ||
  null;

const enviarGHL = [
  'ESCALADO',
  'CITA_CONFIRMADA',
  'CITA_CANCELADA',
  'SLOT_OCUPADO',
  'INTENTO_AGENDAR'
].includes(tipoEvento);

return [{
  json: {
    ...input,

    tipoEvento,
    enviarGHL,

    crmEvento: {
      ...(input.crmEvento || {}),

      tipo_evento: tipoEvento,
      conversation_id: raw.conversation_id || input.conversationId,
      patient_id: input.patientId || input.context?.patientId || '',

      canal: input.channel,
      paciente_nombre: nombre,
      paciente_telefono: telefono,

      servicio,
      cita_fecha: input.slotInicio || input.crmEvento?.cita_fecha || '',
      calendar_event_id: input.calendarEventId || input.crmEvento?.calendar_event_id || '',

      requiere_atencion: tipoEvento === 'ESCALADO' ? 'true' : 'false',
      prioridad: tipoEvento === 'ESCALADO' ? 'ALTA' : 'MEDIA',
      etapa_actual: input.context?.stage || input.nuevaEtapa || '',

      mensaje_paciente: input._webhookData?.message || input.crmEvento?.mensaje_paciente || '',
      respuesta_bot: input.message || input.respuestaIA || input.crmEvento?.respuesta_bot || '',

      notas_staff: motivo || '',
      timestamp: new Date().toISOString()
    }
  }
}];

const original = $('Preparar Respuesta Final').first().json;

return [{
  json: {
    ...original,
    contextoGuardado: true,
    pacienteGuardado: true
  }
}];

const original = $('Preparar Email Staff').first().json;

return [{
  json: {
    ...original,
    emailEnviado: true,
    emailResponse: $input.first().json
  }
}];

const items = $input.all().map(i => i.json);

const base = items.find(i =>
  i.slotInicio ||
  i.slotElegidoMotor ||
  i.context?.metadata?.slotPropuesto
) || {};

const slotInicio = base.slotInicio || base.slotElegidoMotor?.inicio || base.context?.metadata?.slotPropuesto?.inicio;
const slotFin = base.slotFin || base.slotElegidoMotor?.fin || base.context?.metadata?.slotPropuesto?.fin;

const si = new Date(slotInicio);
const sf = new Date(slotFin);

const eventos = items.filter(i => i.start && i.end);

const eventosQueChocan = eventos.filter(e => {
  const ei = new Date(e.start.dateTime || e.start.date);
  const ef = new Date(e.end.dateTime || e.end.date);

  return si < ef && sf > ei;
});

return [{
  json: {
    ...base,
    slotOcupado: eventosQueChocan.length > 0,
    eventosCalendarOcupados: eventos.length,
    eventosQueChocan
  }
}];

const input = $input.first().json;

const contactId =
  input.contact?.id ||
  input.id ||
  input.contactId ||
  '';

const originalOpportunity = input.ghl?.opportunityPayload || {};
const originalNote = input.ghl?.notePayload || {};

return [{
  json: {
    ...input,

    ghlContactId: contactId,

    ghlOpportunityPayload: {
      ...originalOpportunity,
      locationId: originalOpportunity.locationId || $env.GHL_LOCATION_ID,
      pipelineId: originalOpportunity.pipelineId || $env.GHL_PIPELINE_ID,
      pipelineStageId: originalOpportunity.pipelineStageId || $env.GHL_STAGE_ESCALADO,
      contactId,
      name: originalOpportunity.name || `Consulta - ${input.contact?.firstName || ''}`.trim(),
      monetaryValue: originalOpportunity.monetaryValue || 0,
      status: originalOpportunity.status || 'open'
    },

    ghlNotePayload: {
      ...originalNote
    }
  }
}];
